"use client";

import { FormEvent, useState } from "react";

type MangaResult = {
  title: string;
  synopsis: string;
  coverImage: string | null;
  malId: number;
  mangaDexId: string | null;
};

const featuredTitles = [
  {
    title: "Berserk",
    tag: "Dark fantasy",
    note: "Brutalist violence, mythic scale, iconic black-ink intensity.",
  },
  {
    title: "Vagabond",
    tag: "Seinen classic",
    note: "Meditative swordsmanship with painterly motion and silence.",
  },
  {
    title: "Monster",
    tag: "Psychological",
    note: "European noir tension, ethical dread, unforgettable pacing.",
  },
];

function Badge({ label, value }: { label: string; value: string | number | null }) {
  return (
    <div className="rounded-full border border-[var(--line)] bg-white/5 px-4 py-2 text-sm text-stone-200 backdrop-blur">
      <span className="mr-2 text-stone-400">{label}</span>
      <span className="font-semibold text-white">{value ?? "Not available"}</span>
    </div>
  );
}

function ShelfCard({
  title,
  tag,
  note,
}: {
  title: string;
  tag: string;
  note: string;
}) {
  return (
    <article className="group relative overflow-hidden rounded-[28px] border border-[var(--line)] bg-[rgba(255,255,255,0.03)] p-5 transition duration-300 hover:-translate-y-1 hover:bg-[rgba(255,255,255,0.05)]">
      <div className="absolute inset-0 bg-[linear-gradient(180deg,rgba(214,162,94,0.12),transparent_45%)] opacity-80" />
      <div className="relative flex h-full flex-col justify-between gap-8">
        <div>
          <p className="text-xs uppercase tracking-[0.28em] text-[var(--accent-strong)]">
            {tag}
          </p>
          <h3 className="font-display mt-3 text-3xl font-semibold text-white">{title}</h3>
        </div>
        <p className="max-w-xs text-sm leading-7 text-stone-300">{note}</p>
      </div>
    </article>
  );
}

export default function HomePage() {
  const [query, setQuery] = useState("");
  const [result, setResult] = useState<MangaResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function handleSearch(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    if (!query.trim()) {
      setError("Type a manga title to begin.");
      setResult(null);
      return;
    }

    setLoading(true);
    setError("");

    try {
      const response = await fetch(`/api/manga?search=${encodeURIComponent(query)}`);
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || "Search could not be completed.");
      }

      setResult(data);
    } catch (err) {
      setResult(null);
      setError(err instanceof Error ? err.message : "An unexpected error occurred.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <main className="min-h-screen px-6 py-10 text-white md:px-10 md:py-12">
      <div className="mx-auto flex max-w-6xl flex-col gap-10">
        <section className="relative overflow-hidden rounded-[36px] border border-[var(--line)] bg-[var(--card)] p-8 shadow-[0_30px_120px_rgba(0,0,0,0.45)] backdrop-blur-xl md:p-10">
          <div className="absolute inset-0 bg-[linear-gradient(135deg,rgba(214,162,94,0.16),transparent_35%,rgba(255,255,255,0.03)_100%)]" />
          <div className="absolute -right-16 top-10 h-40 w-40 rounded-full bg-[rgba(214,162,94,0.16)] blur-3xl" />
          <div className="absolute -left-10 bottom-0 h-32 w-32 rounded-full bg-[rgba(255,255,255,0.05)] blur-3xl" />

          <div className="relative mb-8 max-w-3xl">
            <p className="mb-4 inline-flex rounded-full border border-[rgba(214,162,94,0.24)] bg-[rgba(214,162,94,0.12)] px-4 py-1 text-sm uppercase tracking-[0.28em] text-[var(--accent-strong)]">
              Editorial manga discovery
            </p>
            <h1 className="font-display text-6xl font-semibold tracking-[0.02em] text-white md:text-8xl">
              Mangastoon
            </h1>
            <p className="mt-4 max-w-2xl text-base leading-8 text-stone-300 md:text-lg">
              Search any manga and unify the visual metadata from MyAnimeList
              with the internal MangaDex identifier in one elegant view.
            </p>
          </div>

          <form onSubmit={handleSearch} className="relative flex flex-col gap-4 md:flex-row">
            <input
              type="text"
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="Try Berserk, Vagabond, Monster..."
              className="h-14 flex-1 rounded-2xl border border-[var(--line)] bg-[rgba(8,8,8,0.65)] px-5 text-base text-white outline-none ring-0 transition placeholder:text-stone-500 focus:border-[var(--accent)]"
            />
            <button
              type="submit"
              disabled={loading}
              className="h-14 rounded-2xl bg-[var(--accent)] px-6 font-semibold text-[var(--accent-ink)] transition hover:bg-[var(--accent-strong)] disabled:cursor-not-allowed disabled:opacity-60"
            >
              {loading ? "Searching..." : "Search manga"}
            </button>
          </form>

          {error ? (
            <div className="relative mt-5 rounded-2xl border border-rose-300/20 bg-rose-300/10 px-4 py-3 text-sm text-rose-100">
              {error}
            </div>
          ) : null}
        </section>

        <section>
          <div className="mb-5 flex items-end justify-between gap-4">
            <div>
              <p className="text-sm uppercase tracking-[0.28em] text-[var(--accent-strong)]">
                Featured shelf
              </p>
              <h2 className="font-display mt-2 text-4xl font-semibold text-white">
                Curated entry points
              </h2>
            </div>
            <p className="max-w-md text-sm leading-7 text-stone-400">
              A starter shelf to make the landing feel alive before the first search.
            </p>
          </div>

          <div className="grid gap-4 md:grid-cols-3">
            {featuredTitles.map((item) => (
              <ShelfCard key={item.title} title={item.title} tag={item.tag} note={item.note} />
            ))}
          </div>
        </section>

        <section>
          {loading ? (
            <div className="grid animate-pulse gap-6 rounded-[30px] border border-[var(--line)] bg-[var(--card)] p-6 backdrop-blur-xl md:grid-cols-[260px_1fr]">
              <div className="h-[360px] rounded-3xl bg-white/10" />
              <div className="space-y-4">
                <div className="h-8 w-2/3 rounded-full bg-white/10" />
                <div className="h-5 w-full rounded-full bg-white/10" />
                <div className="h-5 w-11/12 rounded-full bg-white/10" />
                <div className="h-5 w-10/12 rounded-full bg-white/10" />
                <div className="flex gap-3 pt-4">
                  <div className="h-10 w-40 rounded-full bg-white/10" />
                  <div className="h-10 w-48 rounded-full bg-white/10" />
                </div>
              </div>
            </div>
          ) : null}

          {!loading && result ? (
            <article className="grid gap-6 rounded-[30px] border border-[var(--line)] bg-[var(--card)] p-6 shadow-[0_24px_80px_rgba(0,0,0,0.45)] backdrop-blur-xl md:grid-cols-[260px_1fr]">
              <div className="overflow-hidden rounded-3xl border border-[var(--line)] bg-black/40">
                {result.coverImage ? (
                  <img
                    src={result.coverImage}
                    alt={result.title}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full min-h-[360px] items-center justify-center p-6 text-center text-stone-400">
                    No cover available
                  </div>
                )}
              </div>

              <div className="flex flex-col justify-between gap-6">
                <div>
                  <p className="mb-3 text-sm uppercase tracking-[0.25em] text-[var(--accent-strong)]">
                    Search result
                  </p>
                  <h2 className="font-display text-4xl font-semibold text-white md:text-5xl">
                    {result.title}
                  </h2>
                  <p className="mt-4 text-sm leading-7 text-stone-300 md:text-base">
                    {result.synopsis}
                  </p>
                </div>

                <div className="flex flex-wrap gap-3">
                  <Badge label="MyAnimeList ID" value={result.malId} />
                  <Badge label="MangaDex ID" value={result.mangaDexId} />
                </div>
              </div>
            </article>
          ) : null}
        </section>
      </div>
    </main>
  );
}
